const { db } = require('../config/database');
const bcrypt = require('bcryptjs');
const { v4: uuidv4 } = require('uuid');

class User {
  static tableName = 'users';

  // 创建用户
  static async create(userData) {
    const { username, email, password, phone, role } = userData;
    
    // 加密密码
    const passwordHash = await bcrypt.hash(password, 10);
    
    const [user] = await db(this.tableName)
      .insert({
        id: uuidv4(), // 使用UUID
        username,
        email,
        password_hash: passwordHash,
        phone: phone || null,
        role: role || 'user',
        display_name: username, // 使用用户名作为显示名
        level: 1,
        experience: 0,
        coins: 100,
        gems: 10,
        points: 0,
        total_pixels: 0,
        current_pixels: 0
      })
      .returning('*');
    
    // 创建用户像素状态
    await db('user_pixel_states').insert({
      user_id: user.id,
      last_accum_time: Math.floor(Date.now() / 1000)
    });
    
    return this.sanitizeUser(user);
  }

  // 根据ID查找用户
  static async findById(id) {
    const user = await db(this.tableName)
      .where({ id })
      .first();
    
    return user ? this.sanitizeUser(user) : null;
  }

  // 根据用户名查找用户
  static async findByUsername(username) {
    const user = await db(this.tableName)
      .where({ username })
      .first();
    
    return user ? this.sanitizeUser(user) : null;
  }

  // 根据邮箱查找用户
  static async findByEmail(email) {
    const user = await db(this.tableName)
      .where({ email })
      .first();
    
    return user ? this.sanitizeUser(user) : null;
  }

  // 根据邮箱查找用户（包含密码哈希，用于认证）
  static async findByEmailForAuth(email) {
    const user = await db(this.tableName)
      .where({ email })
      .first();
    
    return user;
  }

  // 根据用户名查找用户（包含密码哈希，用于认证）
  static async findByUsernameForAuth(username) {
    const user = await db(this.tableName)
      .where({ username })
      .first();
    
    return user;
  }

  // 根据手机号查找用户
  static async findByPhone(phone) {
    const user = await db(this.tableName)
      .where({ phone })
      .first();
    
    return user;
  }

  // 验证密码
  static async verifyPassword(user, password) {
    return await bcrypt.compare(password, user.password_hash);
  }

  // 更新用户活动时间
  static async updateActivity(id) {
    await db(this.tableName)
      .where({ id })
      .update({
        last_login: db.fn.now(),
        updated_at: db.fn.now()
      });
  }

  // 更新用户点数
  static async updatePoints(id, points) {
    await db(this.tableName)
      .where({ id })
      .update({
        points,
        updated_at: db.fn.now()
      });
  }

  // 清理用户数据（移除敏感信息）
  static sanitizeUser(user) {
    const { password_hash, ...sanitizedUser } = user;
    return sanitizedUser;
  }
}

module.exports = User;
